// components/ProjectForm.js - Shared form component for Tambah and Edit
import React from 'react';
import { Link } from 'react-router-dom';

export default function ProjectForm({ title, icon, onSubmit, loading, children }) {
  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;500;600;700;800;900&family=Inter:wght@300;400;500;600;700&display=swap');

        * { margin: 0; padding: 0; box-sizing: border-box; }

        body {
          background: #090909;
          color: #F5F5F5;
          font-family: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
          min-height: 100vh;
          overflow-x: hidden;
        }

        body::before {
          content: '';
          position: fixed;
          inset: 0;
          z-index: 0;
          pointer-events: none;
          background-image: 
            radial-gradient(circle at 20% 30%, rgba(255,62,165,0.03) 0%, transparent 50%),
            radial-gradient(circle at 80% 70%, rgba(216,167,177,0.03) 0%, transparent 50%);
        }

        .form-page {
          max-width: 720px;
          margin: 0 auto;
          padding: 40px 20px;
          position: relative;
          z-index: 1;
          min-height: 100vh;
        }

        .form-header {
          display: flex;
          justify-content: space-between;
          align-items: center;
          margin-bottom: 32px;
          flex-wrap: wrap;
          gap: 12px;
        }

        .form-title {
          font-family: 'Space Grotesk', sans-serif;
          font-weight: 800;
          font-size: 1.8rem;
          letter-spacing: -0.5px;
          color: #F5F5F5;
        }

        .form-title .highlight {
          background: linear-gradient(135deg, #FF3EA5, #FF7CC7);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .form-back {
          display: inline-flex;
          align-items: center;
          gap: 6px;
          padding: 8px 18px;
          border-radius: 100px;
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.04);
          color: rgba(255,255,255,0.3);
          text-decoration: none;
          font-size: 0.8rem;
          font-weight: 500;
          transition: all 0.3s ease;
        }

        .form-back:hover {
          background: rgba(255,255,255,0.05);
          color: rgba(255,255,255,0.6);
        }

        .form-glass {
          background: rgba(255,255,255,0.02);
          border-radius: 24px;
          border: 1px solid rgba(255,255,255,0.04);
          padding: 40px;
        }

        .form-glass .form-label {
          font-family: 'Inter', sans-serif;
          font-weight: 500;
          font-size: 0.8rem;
          color: rgba(255,255,255,0.4);
          margin-bottom: 6px;
          text-transform: uppercase;
          letter-spacing: 0.3px;
        }

        .form-glass .form-control,
        .form-glass .form-select {
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.04);
          border-radius: 12px;
          padding: 12px 16px;
          font-family: 'Inter', sans-serif;
          font-size: 0.9rem;
          color: #F5F5F5;
          transition: all 0.3s ease;
          width: 100%;
        }

        .form-glass .form-control:focus,
        .form-glass .form-select:focus {
          background: rgba(255,255,255,0.04);
          border-color: rgba(255,62,165,0.15);
          box-shadow: 0 0 0 3px rgba(255,62,165,0.04);
          outline: none;
        }

        .form-glass .form-control::placeholder {
          color: rgba(255,255,255,0.15);
        }

        .form-glass textarea.form-control {
          resize: vertical;
          min-height: 100px;
        }

        .form-glass .form-check {
          display: flex;
          align-items: center;
          gap: 10px;
          padding: 6px 0;
        }

        .form-glass .form-check-input {
          width: 18px;
          height: 18px;
          border-radius: 6px;
          background: rgba(255,255,255,0.03);
          border: 1px solid rgba(255,255,255,0.06);
          cursor: pointer;
          transition: all 0.3s ease;
          flex-shrink: 0;
        }

        .form-glass .form-check-input:checked {
          background: rgba(255,62,165,0.15);
          border-color: rgba(255,62,165,0.2);
        }

        .form-glass .form-check-input:focus {
          box-shadow: 0 0 0 3px rgba(255,62,165,0.05);
        }

        .form-glass .form-check-label {
          font-family: 'Inter', sans-serif;
          font-size: 0.85rem;
          color: rgba(255,255,255,0.5);
          cursor: pointer;
        }

        .form-glass .current-img {
          max-width: 120px;
          max-height: 80px;
          object-fit: cover;
          border-radius: 8px;
          border: 1px solid rgba(255,255,255,0.04);
          margin-top: 8px;
        }

        .form-glass .text-light {
          color: rgba(255,255,255,0.2) !important;
          font-size: 0.7rem;
          margin-top: 4px;
          display: block;
        }

        .form-glass .btn-submit {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          padding: 14px 32px;
          border-radius: 100px;
          background: rgba(255,62,165,0.12);
          border: 1px solid rgba(255,62,165,0.12);
          color: #FF7CC7;
          font-family: 'Inter', sans-serif;
          font-weight: 600;
          font-size: 0.9rem;
          cursor: pointer;
          transition: all 0.3s ease;
          width: 100%;
          justify-content: center;
        }

        .form-glass .btn-submit:hover:not(:disabled) {
          background: rgba(255,62,165,0.2);
          border-color: rgba(255,62,165,0.2);
          transform: translateY(-2px);
        }

        .form-glass .btn-submit:disabled {
          opacity: 0.5;
          cursor: not-allowed;
        }

        @media (max-width: 768px) {
          .form-page { padding: 20px 16px; }
          .form-glass { padding: 24px; }
          .form-title { font-size: 1.4rem; }
        }

        @media (max-width: 576px) {
          .form-glass { padding: 16px; }
          .form-glass .form-control { padding: 10px 14px; font-size: 0.8rem; }
          .form-glass .btn-submit { padding: 12px 24px; font-size: 0.8rem; }
        }
      `}</style>
      <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" />
      <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.7.2/css/all.min.css" />

      <div className="form-page">
        <div className="form-header">
          <h1 className="form-title">
            <span className="highlight"><i className={`fas ${icon} me-2`}></i>{title}</span>
          </h1>
          <Link to="/admin" className="form-back">
            <i className="fas fa-arrow-left"></i> Back
          </Link>
        </div>

        <div className="form-glass">
          <form onSubmit={onSubmit}>
            {children}
            <button type="submit" className="btn-submit" disabled={loading}>
              {loading ? (
                <><i className="fas fa-spinner fa-spin"></i> Saving...</>
              ) : (
                <><i className={`fas ${icon}`}></i> {title}</>
              )}
            </button>
          </form>
        </div>
      </div>
    </>
  );
}
